#[cfg(test)]
mod tests {
    // use super::*;

    use uplc::tx::SlotConfig;
    use whisky::{MaestroProvider, Network};
    use whisky_common::Evaluator;

    #[tokio::test]
    async fn test_maestro_provider() {
        use dotenv::dotenv;
        use std::env::var;
        dotenv().ok();
        let provider = MaestroProvider::new(var("MAESTRO_API_KEY").unwrap().as_str(), "preprod");
        let tx = "";
        // let chained_tx: Vec<String>= vec!["".to_string(), "".to_string()];
        let result = provider
            .evaluate_tx(tx, &[], &[], &Network::Mainnet, &SlotConfig::default())
            .await;
        match result {
            Ok(actions) => {
                println!("actions: {:?}", actions);
                assert_eq!(actions.len(), 1);
            }
            _ => panic!("Error evaluating tx"),
        }
    }
}
